<?php
require_once(__DIR__ . '/../php/configuracion/auth.php'); require_once(__DIR__ . '/../php/modelo/conexion.php');
$uid=(int)$_SESSION['id'];
$q=$conexion->prepare('SELECT * FROM reservas WHERE usuario_id=? ORDER BY fecha DESC, hora DESC'); $q->bind_param('i',$uid); $q->execute(); $reservas=$q->get_result();
$q=$conexion->prepare('SELECT p.*,d.estado AS estado_domicilio,d.direccion FROM pedidos p LEFT JOIN domicilios d ON d.pedido_id=p.id WHERE p.usuario_id=? ORDER BY p.id DESC'); $q->bind_param('i',$uid); $q->execute(); $pedidos=$q->get_result();
function estadoClase($estado){ return 'estado-'.str_replace(' ','-',strtolower($estado ?: 'pendiente')); }
function progreso($estado){ return $estado==='entregado'?100:($estado==='en camino'?65:25); }
?>
